import React, { useMemo } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  useWindowDimensions,
  Platform,
} from 'react-native';
import MaskedView from '@react-native-masked-view/masked-view';
import { BlurView } from 'expo-blur';
import { LinearGradient } from 'expo-linear-gradient';
import { COLORS, FIGMA_PRODUCT_CARD, FONT, GRADIENTS, RADIUS } from '../constants/theme';
import type { CategoryKey } from '../types';

type IconComponent = React.ComponentType<{ size: number; color: string }>;

interface CategoryPillProps {
  label: CategoryKey;
  icon?: IconComponent;
  isActive: boolean;
  /** Last categories over the cyan accent — Figma: frosted / diffused, not solid R166. */
  frosted?: boolean;
  onPress: (label: CategoryKey) => void;
}

/** Figma Discover 1:38 / Categories 1:46 — 50×50 pills, 28pt icon at 390pt baseline */
const ICON_BASE = 28;

/** R167-style tint over blur (hex → rgba, tuned for 50pt pill). */
const GLASS_OVERLAY = ['rgba(54, 62, 81, 0.42)', 'rgba(25, 30, 38, 0.48)'] as const;
const GLASS_OVERLAY_WEB = ['rgba(54, 62, 81, 0.72)', 'rgba(25, 30, 38, 0.78)'] as const;

export function CategoryPill({ label, icon: Icon, isActive, frosted = false, onPress }: CategoryPillProps) {
  const { width } = useWindowDimensions();
  const scale = width / 390;

  const sx = useMemo(
    () => ({
      up:    20 * scale,
      blur:  30 * scale,
      r:     RADIUS.md * scale,
      icon:  ICON_BASE * scale,
      fs:    13 * scale,
      wAct:  50 * scale,
      hAct:  50 * scale,
      wIn:   50 * scale,
      hIn:   50 * scale,
    }),
    [scale],
  );

  const glowWrap = {
    shadowColor: '#2b3445' as const,
    shadowOffset: { width: 0, height: -sx.up },
    shadowOpacity: 0.5,
    shadowRadius: sx.blur,
    elevation: 0 as const,
  };

  const dropBelow = {
    shadowColor: FIGMA_PRODUCT_CARD.shadowHex,
    shadowOffset: { width: 0, height: sx.up },
    shadowOpacity: 1,
    shadowRadius: sx.blur,
  };

  const pillSize = {
    width:  isActive ? sx.wAct : sx.wIn,
    height: isActive ? sx.hAct : sx.hIn,
    borderRadius: sx.r,
  };

  if (isActive) {
    return (
      <View style={glowWrap}>
        <TouchableOpacity onPress={() => onPress(label)} activeOpacity={0.85}>
          <LinearGradient
            colors={GRADIENTS.accent}
            start={{ x: 0, y: 0 }}
            end={{ x: 1, y: 1 }}
            style={[
              styles.pillBase,
              pillSize,
              dropBelow,
              { elevation: 14 },
            ]}
          >
            {Icon ? (
              <Icon size={sx.icon} color={COLORS.white} />
            ) : (
              <Text style={[styles.labelActive, { fontSize: sx.fs }]}>{label}</Text>
            )}
          </LinearGradient>
        </TouchableOpacity>
      </View>
    );
  }

  if (frosted) {
    const iconColor = COLORS.white;
    const inner = Icon ? (
      <Icon size={sx.icon} color={iconColor} />
    ) : (
      <Text style={[styles.labelInactive, { fontSize: sx.fs }]}>{label}</Text>
    );

    return (
      <View style={glowWrap}>
        <TouchableOpacity onPress={() => onPress(label)} activeOpacity={0.85}>
          <View style={[styles.pillBase, pillSize, dropBelow, styles.frostOuter, { elevation: 10 }]}>
            {Platform.OS === 'web' ? (
              <LinearGradient
                colors={[...GLASS_OVERLAY_WEB]}
                start={{ x: 0.15, y: 0 }}
                end={{ x: 0.85, y: 1 }}
                style={StyleSheet.absoluteFillObject}
              >
                <View style={styles.pillCenter}>{inner}</View>
              </LinearGradient>
            ) : (
              <MaskedView
                style={[StyleSheet.absoluteFillObject, { borderRadius: sx.r, overflow: 'hidden' }]}
                maskElement={
                  <View
                    style={{
                      width:          sx.wIn,
                      height:         sx.hIn,
                      borderRadius:   sx.r,
                      backgroundColor: '#FFFFFF',
                    }}
                  />
                }
              >
                <BlurView
                  intensity={34}
                  tint="dark"
                  experimentalBlurMethod={Platform.OS === 'android' ? 'dimezisBlurView' : undefined}
                  blurReductionFactor={Platform.OS === 'android' ? 3.2 : undefined}
                  style={{ width: sx.wIn, height: sx.hIn }}
                />
                <LinearGradient
                  colors={[...GLASS_OVERLAY]}
                  start={{ x: 0.15, y: 0 }}
                  end={{ x: 0.85, y: 1 }}
                  style={StyleSheet.absoluteFillObject}
                  pointerEvents="none"
                >
                  <View style={styles.pillCenter}>{inner}</View>
                </LinearGradient>
              </MaskedView>
            )}
          </View>
        </TouchableOpacity>
      </View>
    );
  }

  // Inactive solid — R166 fill (pills over navy)
  return (
    <View style={glowWrap}>
      <TouchableOpacity onPress={() => onPress(label)} activeOpacity={0.85}>
        <LinearGradient
          colors={[FIGMA_PRODUCT_CARD.r166.fill0, FIGMA_PRODUCT_CARD.r166.fill1]}
          start={{ x: 0.15, y: 0 }}
          end={{ x: 0.85, y: 1 }}
          style={[
            styles.pillBase,
            pillSize,
            dropBelow,
            { elevation: 10 },
          ]}
        >
          {Icon ? (
            <Icon size={sx.icon} color={COLORS.textLo} />
          ) : (
            <Text style={[styles.labelInactive, { fontSize: sx.fs }]}>{label}</Text>
          )}
        </LinearGradient>
      </TouchableOpacity>
    </View>
  );
}

const styles = StyleSheet.create({
  pillBase: {
    alignItems:     'center',
    justifyContent: 'center',
    overflow:       'hidden',
  },
  frostOuter: {
    overflow: 'hidden',
  },
  pillCenter: {
    flex:           1,
    alignItems:     'center',
    justifyContent: 'center',
  },
  labelActive: {
    fontFamily: FONT.medium,
    color:       COLORS.white,
  },
  labelInactive: {
    fontFamily: FONT.medium,
    color:       COLORS.textLo,
  },
});

