/**
 * Swipe-to-confirm checkout control (Figma Cart 1:210 / node 1:230).
 *
 * Track: pill capsule, inset from screen; muted fill + hairline border.
 * Thumb: rounded square gradient + chevron, no outer stroke; slides L→R.
 * Label: “Checkout” centered in the space to the right of the thumb slot.
 */
import React, { useCallback } from 'react';
import { StyleSheet, Text, View, useWindowDimensions } from 'react-native';
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  runOnJS,
  interpolate,
  Extrapolation,
} from 'react-native-reanimated';
import { Gesture, GestureDetector } from 'react-native-gesture-handler';
import { LinearGradient } from 'expo-linear-gradient';
import { COLORS, CHECKOUT_TRACK_WIDTH_PT, FONT, GRADIENTS } from '../constants/theme';

interface CheckoutSliderProps {
  onConfirm?: () => void;
}

const DESIGN_BASELINE = 390;
/** Figma 1:230 — track height (pt @ baseline). */
const TRACK_H = 46;
/** Thumb fits inside track with horizontal / vertical inset. */
const THUMB = 40;
const THUMB_PAD = 3;

export function CheckoutSlider({ onConfirm }: CheckoutSliderProps) {
  const { width } = useWindowDimensions();
  const scale = width / DESIGN_BASELINE;
  // Figma width @390, never wider than ~80% of screen or less than ~24pt side margins
  const TRACK_WIDTH = Math.min(
    CHECKOUT_TRACK_WIDTH_PT * scale,
    width * 0.8,
    width - 48,
  );
  const MAX_DRAG = TRACK_WIDTH - THUMB_PAD * 2 - THUMB;

  const translateX = useSharedValue(0);

  const confirm = useCallback(() => {
    onConfirm?.();
  }, [onConfirm]);

  const pan = Gesture.Pan()
    .onChange((e) => {
      'worklet';
      translateX.value = Math.max(0, Math.min(e.translationX, MAX_DRAG));
    })
    .onEnd(() => {
      'worklet';
      if (translateX.value >= MAX_DRAG * 0.7) {
        translateX.value = withSpring(MAX_DRAG, { damping: 18, stiffness: 120 }, () => {
          runOnJS(confirm)();
        });
      } else {
        translateX.value = withSpring(0, { damping: 18, stiffness: 120 });
      }
    });

  const thumbStyle = useAnimatedStyle(() => ({
    transform: [{ translateX: translateX.value }],
  }));

  const labelOpacity = useAnimatedStyle(() => ({
    opacity: interpolate(
      translateX.value,
      [0, MAX_DRAG * 0.5],
      [1, 0],
      Extrapolation.CLAMP,
    ),
    transform: [
      {
        translateX: interpolate(
          translateX.value,
          [0, MAX_DRAG],
          [0, 12],
          Extrapolation.CLAMP,
        ),
      },
    ],
  }));

  const doneOpacity = useAnimatedStyle(() => ({
    opacity: interpolate(
      translateX.value,
      [MAX_DRAG * 0.5, MAX_DRAG],
      [0, 1],
      Extrapolation.CLAMP,
    ),
  }));

  const labelSlotLeft = THUMB_PAD + THUMB + 10;

  return (
    <View
      style={[
        styles.track,
        {
          width:           TRACK_WIDTH,
          height:          TRACK_H,
          borderRadius:    TRACK_H / 2,
        },
      ]}
    >
      <View
        style={[styles.labelSlot, { left: labelSlotLeft, right: 14 }]}
        pointerEvents="none"
      >
        <Animated.Text style={[styles.checkoutLabel, labelOpacity]}>
          Checkout
        </Animated.Text>
        <Animated.Text style={[styles.doneLabel, doneOpacity]}>
          Done! ✓
        </Animated.Text>
      </View>

      <GestureDetector gesture={pan}>
        <Animated.View
          style={[
            styles.thumbWrap,
            {
              left:   THUMB_PAD,
              top:    (TRACK_H - THUMB) / 2,
              height: THUMB,
            },
            thumbStyle,
          ]}
        >
          <LinearGradient
            colors={GRADIENTS.accent}
            start={{ x: 0, y: 0 }}
            end={{ x: 1, y: 1 }}
            style={styles.thumb}
          >
            <Text style={styles.thumbArrow}>›</Text>
          </LinearGradient>
        </Animated.View>
      </GestureDetector>
    </View>
  );
}

const styles = StyleSheet.create({
  track: {
    backgroundColor: '#252d3a',
    borderWidth: 1,
    borderColor: 'rgba(255,255,255,0.1)',
    overflow: 'hidden',
    justifyContent: 'center',
    shadowColor: '#11161e',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.55,
    shadowRadius: 10,
    elevation: 5,
    alignSelf: 'center',
  },
  labelSlot: {
    position:       'absolute',
    top:            0,
    bottom:         0,
    justifyContent: 'center',
    alignItems:     'center',
  },
  thumbWrap: {
    position: 'absolute',
    justifyContent: 'center',
  },
  thumb: {
    width:          THUMB,
    height:         THUMB,
    borderRadius:   10,
    alignItems:     'center',
    justifyContent: 'center',
    shadowColor:    '#10141c',
    shadowOffset:   { width: 0, height: 10 },
    shadowOpacity:  0.45,
    shadowRadius:   16,
    elevation:      8,
  },
  thumbArrow: {
    fontSize:   20,
    color:      COLORS.white,
    fontFamily: FONT.bold,
    lineHeight: 24,
    marginLeft: 1,
  },
  checkoutLabel: {
    position:       'absolute',
    fontFamily:     FONT.medium,
    fontSize:       15,
    color:          COLORS.textLo,
    letterSpacing:  -0.08,
    textAlign:      'center',
    alignSelf:      'stretch',
  },
  doneLabel: {
    position:       'absolute',
    fontFamily:     FONT.semibold,
    fontSize:       15,
    color:          COLORS.accentA,
    letterSpacing:  -0.08,
    textAlign:      'center',
    alignSelf:      'stretch',
  },
});

